function TabIcon({ tab, color }: { tab: TabName; color: string }) {
  return (
    <Svg width={24} height={24} viewBox="0 0 28 28" fill="none">
      {ICON_PATHS[tab].map((d, i) => (
        <Path key={i} fillRule="evenodd" clipRule="evenodd" d={d} fill={color} />
      ))}
    </Svg>
  );
}

