export default function TabBar({ activeTab, onTabPress }: TabBarProps) {
  const { colors } = useTheme();
  const [contactVisible, setContactVisible] = useState(false);
  const fadeAnim = useRef(new Animated.Value(0)).current;
  const scaleAnim = useRef(new Animated.Value(0.8)).current;

  const isDark = colors.tabBarBackground === '#1E293B';

  const openContact = () => {
    setContactVisible(true);
    Animated.parallel([
      Animated.timing(fadeAnim, {
        toValue: 1,
        duration: 200,
        useNativeDriver: true,
      }),
      Animated.spring(scaleAnim, {
        toValue: 1,
        damping: 15,
        stiffness: 200,
        useNativeDriver: true,
      }),
    ]).start();
  };

  const closeContact = () => {
    Animated.parallel([
      Animated.timing(fadeAnim, {
        toValue: 0,
        duration: 150,
        useNativeDriver: true,
      }),
      Animated.timing(scaleAnim, {
        toValue: 0.8,
        duration: 150,
        useNativeDriver: true,
      }),
    ]).start(() => setContactVisible(false));
  };

  const openTelegram = () => {
    closeContact();
    Linking.openURL('https://t.me/mike_cashflow');
  };

  const openEmail = () => {
    closeContact();
    Linking.openURL('mailto:mike@cashflow.fun');
  };

  const borderColor = isDark
    ? 'rgba(255, 255, 255, 0.12)'
    : 'rgba(0, 0, 0, 0.08)';

  const blurBg = isDark
    ? 'rgba(30, 41, 59, 0.35)'
    : 'rgba(255, 255, 255, 0.25)';

  return (
    <>
      <View style={styles.tabBarContainer}>
        <LinearGradient
          colors={colors.tabBarGlow}
          style={styles.tabBarGlow}
        />
        <View style={styles.tabBarRow}>
          {/* Main tab pill */}
          <View style={[styles.tabBar, { borderColor, overflow: 'hidden' }]}>
            <BlurView
              style={StyleSheet.absoluteFill}
              blurType={isDark ? 'dark' : 'xlight'}
              blurAmount={20}
              reducedTransparencyFallbackColor={colors.tabBarBackground}
            />
            <View style={[StyleSheet.absoluteFill, { backgroundColor: blurBg }]} />
            {TAB_ORDER.map((tab) => {
              const isActive = activeTab === tab;
              const color = isActive ? colors.tabActiveColor : colors.tabInactiveColor;
              return (
                <TouchableOpacity
                  key={tab}
                  style={styles.tabItem}
                  onPress={() => onTabPress(tab)}
                >
                  <TabIcon tab={tab} color={color} />
                  <Text style={{ fontSize: 10, fontWeight: '500', color }}>
                    {TAB_LABELS[tab]}
                  </Text>
                </TouchableOpacity>
              );
            })}
          </View>

          {/* Contact circle button */}
          <View style={[styles.contactCircle, { borderColor, overflow: 'hidden' }]}>
            <BlurView
              style={StyleSheet.absoluteFill}
              blurType={isDark ? 'dark' : 'xlight'}
              blurAmount={20}
              reducedTransparencyFallbackColor={colors.tabBarBackground}
            />
            <View style={[StyleSheet.absoluteFill, { backgroundColor: blurBg }]} />
            <TouchableOpacity
              style={styles.contactTouchable}
              onPress={openContact}
            >
              <ChatIcon color={colors.tabInactiveColor} />
              <Text style={{ fontSize: 10, fontWeight: '500', color: colors.tabInactiveColor }}>
                Chat
              </Text>
            </TouchableOpacity>
          </View>
        </View>
      </View>

      {/* Contact popup modal */}
      <Modal
        visible={contactVisible}
        transparent
        animationType="none"
        statusBarTranslucent
        onRequestClose={closeContact}
      >
        <View style={styles.modalContainer}>
          <Animated.View style={[styles.overlay, { opacity: fadeAnim, backgroundColor: colors.overlay }]}>
            <TouchableOpacity style={styles.overlayTouchable} activeOpacity={1} onPress={closeContact} />
          </Animated.View>

          <Animated.View
            style={[
              styles.popup,
              {
                backgroundColor: colors.card,
                borderColor: colors.border,
                opacity: fadeAnim,
                transform: [{ scale: scaleAnim }],
              },
            ]}
          >
            <Text style={[styles.popupTitle, { color: colors.textPrimary }]}>Contact us</Text>

            <TouchableOpacity style={[styles.popupOption, { backgroundColor: colors.cardSecondary }]} onPress={openTelegram}>
              <TelegramIcon />
              <View style={styles.popupOptionText}>
                <Text style={[styles.popupOptionLabel, { color: colors.textPrimary }]}>Telegram</Text>
                <Text style={[styles.popupOptionValue, { color: colors.textSecondary }]}>@mike_cashflow</Text>
              </View>
            </TouchableOpacity>

            <TouchableOpacity style={[styles.popupOption, { backgroundColor: colors.cardSecondary }]} onPress={openEmail}>
              <EmailIcon />
              <View style={styles.popupOptionText}>
                <Text style={[styles.popupOptionLabel, { color: colors.textPrimary }]}>Email</Text>
                <Text style={[styles.popupOptionValue, { color: colors.textSecondary }]}>mike@cashflow.fun</Text>
              </View>
            </TouchableOpacity>
          </Animated.View>
        </View>
      </Modal>
    </>
  );
}

